var swapNodes = function(head, k) {
    let first = head;
    for (let i = 0; i < k - 1; i++) {
        first = first.next;
    }
    let second = head;
    let runner = first;
    while (runner.next) {
        runner = runner.next;
        second = second.next;
    }
    const tmp = first.val;
    first.val = second.val;
    second.val = tmp;
    return head;
};
